import type { DatamodelEnum } from '@prisma/dmmf'

/** Generates a TypeScript string union type for a Prisma enum. */
export function generateEnum(enumDef: DatamodelEnum): string {
  const members = enumDef.values.map((v) => `  | '${v.name}'`).join('\n')
  const doc = enumDef.documentation ? `/** ${enumDef.documentation} */\n` : ''
  return `${doc}export type ${enumDef.name} =\n${members}\n`
}

