import type { Field, Model } from '@prisma/dmmf'

import { mapScalarType } from './scalar-type-map'

/** Resolves the TypeScript type string for a single DMMF field. */
function fieldType(field: Field): string {
  let tsType: string

  switch (field.kind) {
    case 'scalar':
      tsType = mapScalarType(field.type)
      break
    case 'enum':
      tsType = field.type
      break
    case 'object':
      tsType = field.type
      break
    case 'unsupported':
    default:
      tsType = 'unknown'
      break
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }
  if (!field.isRequired && !field.isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

/** Generates a TypeScript interface for a Prisma model. */
export function generateModelInterface(model: Model): string {
  const doc = model.documentation ? `/** ${model.documentation} */\n` : ''
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const fieldDoc = f.documentation ? `  /** ${f.documentation} */\n` : ''
      return `${fieldDoc}  ${f.name}: ${fieldType(f)}`
    })
    .join('\n')

  return `${doc}export interface ${model.name} {\n${fields}\n}\n`
}

/**
 * Generates the `CreateInput` and `UpdateInput` helper types for a model.
 * - CreateInput omits auto-generated fields (id with default, createdAt, updatedAt).
 * - UpdateInput makes all fields from CreateInput optional via Partial.
 */
export function generateInputTypes(model: Model): string {
  const scalarFields = model.fields.filter((f) => f.kind !== 'object')

  const createFields = scalarFields
    .filter((f) => !f.isGenerated && !f.isUpdatedAt)
    .map((f) => {
      const optional = f.hasDefaultValue || !f.isRequired
      const tsType = fieldType(f)
      const fieldDoc = f.documentation ? `  /** ${f.documentation} */\n` : ''
      return `${fieldDoc}  ${f.name}${optional ? '?' : ''}: ${tsType}`
    })
    .join('\n')

  const updateFields = scalarFields
    .filter((f) => !f.isGenerated && !f.isUpdatedAt && !f.isId)
    .map((f) => {
      const tsType = fieldType(f)
      const fieldDoc = f.documentation ? `  /** ${f.documentation} */\n` : ''
      return `${fieldDoc}  ${f.name}?: ${tsType}`
    })
    .join('\n')

  return [
    `export interface ${model.name}CreateInput {\n${createFields}\n}\n`,
    `export interface ${model.name}UpdateInput {\n${updateFields}\n}\n`,
  ].join('\n')
}

