import fs from 'node:fs'
import path from 'node:path'

import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generate-client'

/** Prisma generator that emits a typed REST API client with CRUD methods for each model. */
export class PrismaRestClientGenerator implements Generator {
  readonly name = 'prisma-rest-client'

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      prettyName: 'Prisma REST Client',
      defaultOutput: './generated/rest-client',
      requiresEngines: [],
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = options.generator.output?.value
    if (!outputDir) {
      throw new Error('@prisma/client-generator-rest: No output directory specified.')
    }

    const source = generateRestClient({ dmmf: options.dmmf })

    await fs.promises.mkdir(outputDir, { recursive: true })
    await fs.promises.writeFile(path.join(outputDir, 'index.ts'), source, 'utf-8')
  }
}

