import type { Document } from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { generateRestClient } from '../generate-client'

function createDmmf(overrides: Partial<Document['datamodel']> = {}): Document {
  return {
    datamodel: {
      models: [],
      enums: [],
      types: [],
      indexes: [],
      ...overrides,
    },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: {},
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  } as unknown as Document
}

describe('generateRestClient', () => {
  it('generates header comment for empty schema', () => {
    const output = generateRestClient({ dmmf: createDmmf() })
    expect(output).toContain('auto-generated by @prisma/client-generator-rest')
    expect(output).toContain('Do not edit manually')
  })

  it('generates an enum type', () => {
    const dmmf = createDmmf({
      enums: [
        {
          name: 'Role',
          values: [
            { name: 'ADMIN', dbName: null },
            { name: 'USER', dbName: null },
          ],
        },
      ],
    })
    const output = generateRestClient({ dmmf })
    expect(output).toContain("export type Role =\n  | 'ADMIN'\n  | 'USER'")
  })

  it('generates model interface with scalar fields', () => {
    const dmmf = createDmmf({
      models: [
        {
          name: 'User',
          dbName: null,
          schema: null,
          fields: [
            {
              kind: 'scalar',
              name: 'id',
              isRequired: true,
              isList: false,
              isUnique: true,
              isId: true,
              isReadOnly: false,
              hasDefaultValue: true,
              type: 'Int',
              default: { name: 'autoincrement', args: [] },
            },
            {
              kind: 'scalar',
              name: 'email',
              isRequired: true,
              isList: false,
              isUnique: true,
              isId: false,
              isReadOnly: false,
              hasDefaultValue: false,
              type: 'String',
            },
            {
              kind: 'scalar',
              name: 'name',
              isRequired: false,
              isList: false,
              isUnique: false,
              isId: false,
              isReadOnly: false,
              hasDefaultValue: false,
              type: 'String',
            },
          ],
          uniqueFields: [],
          uniqueIndexes: [],
          primaryKey: null,
        },
      ],
    })

    const output = generateRestClient({ dmmf })

    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: number')
    expect(output).toContain('  email: string')
    expect(output).toContain('  name: string | null')
  })

  it('generates CreateInput with optional fields for defaults', () => {
    const dmmf = createDmmf({
      models: [
        {
          name: 'Post',
          dbName: null,
          schema: null,
          fields: [
            {
              kind: 'scalar',
              name: 'id',
              isRequired: true,
              isList: false,
              isUnique: true,
              isId: true,
              isReadOnly: false,
              hasDefaultValue: true,
              type: 'Int',
              default: { name: 'autoincrement', args: [] },
            },
            {
              kind: 'scalar',
              name: 'title',
              isRequired: true,
              isList: false,
              isUnique: false,
              isId: false,
              isReadOnly: false,
              hasDefaultValue: false,
              type: 'String',
            },
          ],
          uniqueFields: [],
          uniqueIndexes: [],
          primaryKey: null,
        },
      ],
    })

    const output = generateRestClient({ dmmf })

    expect(output).toContain('export interface PostCreateInput {')
    // id has a default value so should be optional
    expect(output).toContain('  id?: number')
    // title is required and has no default
    expect(output).toContain('  title: string')
  })

  it('generates UpdateInput without id field', () => {
    const dmmf = createDmmf({
      models: [
        {
          name: 'Post',
          dbName: null,
          schema: null,
          fields: [
            {
              kind: 'scalar',
