    expect(output).toContain('export class PrismaRestClient {')
    expect(output).toContain('constructor(options: RestClientOptions)')
  })

  it('uses number for Int id type in CRUD methods', () => {
    const dmmf = createDmmf({
      models: [
        {
          name: 'Post',
          dbName: null,
          schema: null,
          fields: [
            {
              kind: 'scalar',
