              isRequired: true,
              isList: false,
              isUnique: true,
              isId: true,
              isReadOnly: false,
              hasDefaultValue: true,
              type: 'Int',
              default: { name: 'autoincrement', args: [] },
            },
          ],
          uniqueFields: [],
          uniqueIndexes: [],
          primaryKey: null,
        },
      ],
    })

    const output = generateRestClient({ dmmf })
    expect(output).toContain('async postFindUnique(id: number)')
    expect(output).toContain('async postUpdate(id: number,')
    expect(output).toContain('async postDelete(id: number)')
  })

  it('generates list field types correctly', () => {
    const dmmf = createDmmf({
      models: [
        {
